<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Registrar pago manual</title><link rel="stylesheet" href="<?=BASE_URL?>/public/css/estilos.css"><link rel="stylesheet" href="<?=BASE_URL?>/public/css/admin.css"></head><body class="admin-page"><?php require __DIR__.'/../partials/navbar.php';?><div class="admin-layout"><?php require __DIR__.'/../partials/sidebar.php';?><main class="admin-main"><h1>Registrar pago manual</h1><form class="admin-payment-form" method="post" action="<?=BASE_URL?>/index.php?ruta=admin-pago-manual-guardar"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($csrfToken,ENT_QUOTES,'UTF-8')?>"><label>Adeudo pendiente<select name="id_adeudo" required><option value="">Selecciona</option><?php foreach($adeudos as $a):?><option value="<?=(int)$a['id_adeudo']?>"><?=htmlspecialchars($a['matricula'].' - '.$a['nombre'].' - '.PeriodoHelper::formatear($a['periodo']).' - $'.number_format((float)$a['total'],2),ENT_QUOTES,'UTF-8')?></option><?php endforeach;?></select></label><label>Método<select name="metodo" required><?php foreach(['Efectivo','Transferencia','Depósito','Otro'] as $m):?><option><?=$m?></option><?php endforeach;?></select></label><label>Referencia opcional<input name="referencia" maxlength="100"></label><label>Observaciones opcionales<textarea name="observaciones" maxlength="255"></textarea></label><button>Registrar pago</button><a href="<?=BASE_URL?>/index.php?ruta=admin-pagos">Cancelar</a></form></main></div><script src="<?=BASE_URL?>/public/js/admin.js"></script></body></html>
